def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def validate_solution(nums, target):
    if len(nums) < 2:
        return False
    seen = set()
    for num in nums:
        complement = target - num
        if complement in seen:
            return True
        seen.add(num)
    return False

# Updated solve function to include pitfall checks
def solve_with_checks(nums, target):
    if not validate_solution(nums, target):
        return -1, -1
    return solve(nums, target)
